prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?task bbo:name ?taskName . }
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?modelName ?modelId WHERE {
  VALUES ?id { "4ccc3fd711004f519782ac92e58f6ddd" }
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         ( tai:normalizedId ?id || tai:originalId ?id || tai:modelCreated ?_created ).
  OPTIONAL { ?model tai:normalizedId ?modelId }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?task bbo:name ?taskName . }
}
ORDER BY COALESCE(?taskName, STR(?task))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?modelName ?modelOriginal ?modelNormalized WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName .

  OPTIONAL { ?model tai:originalId ?modelOriginal . }
  OPTIONAL { ?model tai:normalizedId ?modelNormalized . }
  FILTER(
    (BOUND(?modelOriginal) && STR(?modelOriginal) = "4ccc3fd711004f519782ac92e58f6ddd") ||
    (BOUND(?modelNormalized) && STR(?modelNormalized) = "4ccc3fd711004f519782ac92e58f6ddd")
  )

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  OPTIONAL { ?task bbo:name ?taskName . }
}
ORDER BY COALESCE(?taskName, STR(?task))
LIMIT 25
